import { TeamCardTemp } from '../components/Card';
import Testmonial from '../components/Testimonial';
import { useEffect } from 'react';

function OurTeam() {

    useEffect(() => {
        const observer = new IntersectionObserver((entries) => {
            entries.forEach((entry) => {
                if (entry.isIntersecting) {
                    entry.target.classList.add('aos-animate');
                    observer.unobserve(entry.target);
                }
            });
        }, { threshold: 0.05, rootMargin: '0px 0px -50px 0px' });

        const elements = document.querySelectorAll('[data-aos]');
        elements.forEach((el) => observer.observe(el));

        return () => {
            elements.forEach((el) => observer.unobserve(el));
        };
    }, []);

    const teamCardSet = [
        {
            "id": 1, "imagesrc": "grayscale-photo-smiling-woman-wearing-turtleneck-top.jpg", "name": "Alice Johnson", "designation": "Software Engineer"
        },
        { "id": 2, "imagesrc": "front-view-authentic-woman-posing.jpg", "name": "Bob Smith", "designation": "Product Manager" },
        { "id": 3, "imagesrc": "front-view-smiley-woman-posing-black-white.jpg", "name": "Charlie Brown", "designation": "UX Designer" },
        { "id": 4, "imagesrc": "front-view-woman-posing-black-white.jpg", "name": "Diana Lee", "designation": "Quality Analyst" },
    ]
    return (
        <>
            <section >
                <div className='container pt-5'>
                    <div className='row'>
                        <div className='col-md-6 my-5 text-end pe-5' data-aos="fade-right" data-aos-duration="700">
                            <h1>Our Team</h1>
                        </div>
                        <div className='col-md-6 my-5' data-aos="fade-left" data-aos-duration="700">
                            <p>Our team believes in building strong and transparent relationships with both talent and brands. We are committed to providing guidance, support, and clear communication throughout every collaboration. If you have questions, project ideas, or partnership opportunities, our team is here to listen and help you move forward. We value every connection and aim to respond quickly to all inquiries. Reach out to us and our team will guide you through the next steps.</p>
                        </div>
                    </div>
                </div>
            </section >
            <section className='cls-odd'>
                <div className='container pt-5 pb-5'>
                    <div className='row'>
                        <TeamCardTemp teamArr={teamCardSet} />
                    </div>
                </div>
            </section>
            <div className='container pt-5 pb-5'>
                <div className='row'>
                    <TeamCardTemp teamArr={teamCardSet} />
                </div>
            </div>
            <section className='cls-odd'>
                <Testmonial />
            </section>

        </>
    )

}

export default OurTeam;

